interface.definition:
#"SYSTEM_SYSRULES_formLayout"(
  titleBar: #"SYSTEM_SYSRULES_headerTemplateSimple"(
    title: "Create / Update UserPreference",
    secondaryText: "Fill in the fields below and click Save."
  ),
  contents: {
    #"SYSTEM_SYSRULES_textField"(label: "userName", value: ri!record.userName, saveInto: ri!record.userName, required: true),
    #"SYSTEM_SYSRULES_textField"(label: "defaultTemperatureScale", value: ri!record.defaultTemperatureScale, saveInto: ri!record.defaultTemperatureScale, required: true),
    #"SYSTEM_SYSRULES_paragraphField"(label: "favoriteCities", value: ri!record.favoriteCities, saveInto: ri!record.favoriteCities, height: "SHORT"),
    #"SYSTEM_SYSRULES_checkboxField_v1"(label: "notificationsEnabled", value: ri!record.notificationsEnabled, saveInto: ri!record.notificationsEnabled, choiceLabels: {"Yes"}, choiceValues: {true})
  },
  buttons: #"SYSTEM_SYSRULES_buttonLayout"(
    primaryButtons: {
      #"SYSTEM_SYSRULES_buttonWidget_v1"(label: "Save", submit: true, style: "PRIMARY")
    },
    secondaryButtons: {
      #"SYSTEM_SYSRULES_buttonWidget_v1"(label: "Cancel", value: true, saveInto: ri!cancel, submit: true, validate: false)
    }
  )
)
